#if UNITY_EDITOR
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado de ChallengeDefinition (Sistema de Missões/Desafios):
///
/// 1) Desenha "objectives" e "failConditions" com PolymorphicListDrawer
///    (mesmo utilitário das condições/acções de NPC) — "+ Adicionar Objectivo"
///    / "+ Adicionar Condição de Falha" listam automaticamente todas as
///    subclasses de ChallengeObjective/ChallengeFailCondition do projecto.
/// 2) Avisos de validação locais: challengeId/displayName vazios, sem
///    objectivos/sem objectivo obrigatório, restrições de item/habilidade
///    sem 'hasTimeLimit' (ignoradas pelo ChallengeManager — ver tooltip),
///    Provação de Apolo com 'hasTimeLimit' (confirma intenção),
///    recompensas vazias, etc. IDs duplicados entre TODOS os desafios e
///    nomes de variáveis (ActiveVariable/CompletedVariable) duplicados são
///    verificados globalmente por "Animals/Validar Dados do Jogo"
///    (GameDataValidatorWindow, Tarefa #14).
/// </summary>
[CustomEditor(typeof(ChallengeDefinition))]
public class ChallengeDefinitionEditor : Editor
{
    private SerializedProperty _objectivesProp;
    private SerializedProperty _failConditionsProp;

    private void OnEnable()
    {
        _objectivesProp = serializedObject.FindProperty("objectives");
        _failConditionsProp = serializedObject.FindProperty("failConditions");
    }

    public override void OnInspectorGUI()
    {
        serializedObject.Update();
        var challenge = (ChallengeDefinition)target;

        DrawPropertiesExcluding(serializedObject, "m_Script", "objectives", "failConditions");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, _objectivesProp, "Objectivos", typeof(ChallengeObjective), "Adicionar Objectivo");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, _failConditionsProp, "Condições de Falha Adicionais", typeof(ChallengeFailCondition), "Adicionar Condição de Falha");

        serializedObject.ApplyModifiedProperties();

        EditorGUILayout.Space();
        DrawValidationWarnings(challenge);
    }

    private void DrawValidationWarnings(ChallengeDefinition challenge)
    {
        EditorGUILayout.LabelField("Validação", EditorStyles.boldLabel);

        bool anyWarning = false;

        if (string.IsNullOrEmpty(challenge.challengeId))
        {
            EditorGUILayout.HelpBox("\"challengeId\" está vazio — necessário para persistência (PlayerProgress.completedChallengeIds), ranking e para derivar as variáveis \"Desafio_<id>_Ativo\"/\"Desafio_<id>_Concluido\".", MessageType.Warning);
            anyWarning = true;
        }

        if (string.IsNullOrEmpty(challenge.displayName))
        {
            EditorGUILayout.HelpBox("\"displayName\" está vazio — usado no pré-ecrã e no HUD do desafio.", MessageType.Warning);
            anyWarning = true;
        }

        if (challenge.objectives == null || challenge.objectives.Count == 0)
        {
            EditorGUILayout.HelpBox("Sem objectivos definidos — o desafio nunca terminará com sucesso. Adicione pelo menos um objectivo \"obrigatório\".", MessageType.Warning);
            anyWarning = true;
        }
        else
        {
            bool hasRequired = false;
            foreach (var obj in challenge.objectives)
                if (obj != null && obj.required) { hasRequired = true; break; }

            if (!hasRequired)
            {
                EditorGUILayout.HelpBox("Nenhum objectivo está marcado como \"required\" — o desafio nunca terminará com sucesso (todos são opcionais).", MessageType.Warning);
                anyWarning = true;
            }
        }

        bool hasRestrictions = challenge.restrictItemUsage || (challenge.restrictedAbilities != null && challenge.restrictedAbilities.Count > 0);
        if (hasRestrictions && !challenge.hasTimeLimit)
        {
            EditorGUILayout.HelpBox("\"restrictItemUsage\"/\"restrictedAbilities\" estão configurados, mas \"hasTimeLimit\" está desligado — o ChallengeManager IGNORA estas restrições neste caso (para nunca deixar o jogador permanentemente sem itens/habilidades num desafio que pode nunca terminar). Active \"hasTimeLimit\" para que as restrições tenham efeito.", MessageType.Warning);
            anyWarning = true;
        }

        if (challenge.isApoloTrial && challenge.hasTimeLimit)
        {
            EditorGUILayout.HelpBox("\"isApoloTrial\" está activo junto com \"hasTimeLimit\" — confirme que é intencional: a Provação de Apolo normalmente não tem limite de tempo próprio (morrer reinicia a prova, não há \"falha por tempo\").", MessageType.Info);
        }

        if (challenge.challengeType == ChallengeType.ProvacaoDeApolo && !challenge.isApoloTrial)
        {
            EditorGUILayout.HelpBox("\"challengeType\" = ProvacaoDeApolo, mas \"isApoloTrial\" está desligado — sem isto, morrer durante o desafio segue o fluxo normal (checkpoint/Refúgio Seguro) em vez de reiniciar a prova do início (ChallengeManager.RestartApoloTrial, PlayerDeathHandler). Active \"isApoloTrial\" se quiser o comportamento de \"morrer = reiniciar a prova\".", MessageType.Warning);
            anyWarning = true;
        }

        if (challenge.isApoloTrial && challenge.endBehavior != ChallengeEndBehavior.VoltarParaEntrada)
        {
            EditorGUILayout.HelpBox("\"isApoloTrial\" está activo, mas \"endBehavior\" não é VoltarParaEntrada — confirme que é intencional: a Provação de Apolo normalmente devolve o jogador à entrada da prova quando termina (sucesso, falha ou abandono).", MessageType.Info);
        }

        if (challenge.endBehavior == ChallengeEndBehavior.VoltarParaEntrada && challenge.challengeType == ChallengeType.DefesaDeNpc)
        {
            EditorGUILayout.HelpBox("\"endBehavior\" = VoltarParaEntrada com tipo \"DefesaDeNpc\" — confirme que é intencional: desafios de defesa de NPC normalmente usam \"PermanecerNoLocal\" (o jogador continua junto do NPC).", MessageType.Info);
        }

        if (!challenge.primaryReward.HasAnything)
        {
            EditorGUILayout.HelpBox("\"primaryReward\" está vazia — o desafio não concede nenhuma recompensa na primeira conclusão (pode ser intencional, ex: desafio puramente de prestígio/ranking).", MessageType.Info);
        }

        if (challenge.hasSecondaryReward && !challenge.secondaryReward.HasAnything)
        {
            EditorGUILayout.HelpBox("\"hasSecondaryReward\" está activo mas \"secondaryReward\" está vazia — repetições não concederão nada (equivalente a desligar \"hasSecondaryReward\").", MessageType.Info);
        }

        if (!anyWarning && string.IsNullOrEmpty(challenge.description))
        {
            EditorGUILayout.HelpBox("Sugestão: preencha \"description\" — é mostrada no pré-ecrã do desafio.", MessageType.None);
        }
    }
}
#endif
